head.script:
/**
 * 화면 로딩
 */
scwin.onpageload = async function() {

    scwin.strCurrDate = $c.date.getServerDateTime(); // 서버를 기준으로 현재 날짜 반환

	// 세션정보
    scwin.gv_loabranCd = $c.data.getMemInfo("loUpperLobranCd");

    var jsonParams = $c.data.getParameter();
    scwin.gv_odrNo = jsonParams.odrNo;  //파라메터로 받은 원본오더

    scwin.listOdrNo = scwin.gv_odrNo.split(",");        //배열로 변환한 오더
    scwin.txtValue = scwin.gv_odrNo.replace(/,/g,"\n"); //textarea에 표시하기 위한 오더
    scwin.evalRegVal = '/'+scwin.listOdrNo[0]+'/g';

    ed_orderNo.setValue(scwin.listOdrNo[0]);

	const codeOptions = [
        { grpCd: "OP482", compID: "acb_lc_sortCd" }  // 발행순서
    ];
    await $c.data.setCommonCode(codeOptions, function() {
        //작업구분
        acb_lc_sortCd.setValue("6");
    });

    if( scwin.listOdrNo.length == 1 ) {
        tr_addOdr.setStyle("display", "none"); //hide();
    } else {
        tr_addOdr.setStyle("display", "table-row"); //show();
        txt_ta_odrList.setValue(scwin.txtValue.replace(scwin.listOdrNo[0]+"\n", ""));
        $c.gus.cfEnableObj(txt_ta_odrList, "false");
    }

    cb_printCheck.checkAll(true);
    cb_previewCheck.checkAll(true);
};

/**
 * 보고서발행
 */
scwin.btn_print_onclick = async function (e) {
    //validation check
    let ret = await $c.gus.cfValidate([tb_srchCond]);
    if(!ret) {
        return;
    }

    let lenListOdrNo = scwin.listOdrNo.length;

    if(lenListOdrNo == 1) {

        //개별print(viewer 띄운다)
        let data = {
                odiName:"op_202_02_05r",
                reportName: "/ds/op/wrkplan/transwrkplan/op_202_02_05r.ozr",
                odiParam : {
                    odrNo : ed_orderNo.getValue()
                  , sortCd : acb_lc_sortCd.getValue()
                },
                viewerParam : {
                    useprogressbar : true   // 프로그레스바 쓸지 말지
                },
                formParam : {
                }
            };
        let opts = {
			type: 'viewer'
			, printMode: 'view'
			, exportFilename: ''
			, exportMode: 'view'
		};

        if (cb_printCheck.getValue() == "1" && cb_previewCheck.getValue() == "1") { // 인쇄옵션, 미리보기 둘다 체크된 경우
			data.viewerParam.mode = "preview";
			$c.ext.openOzReport(data, opts);
		} else if (cb_printCheck.getValue() == "1") { // 인쇄옵션만 체크된 경우
			$c.ext.printOzReport(data, opts);
		} else if (cb_previewCheck.getValue() == "1") { // 미리보기만 체크된 경우
			opts.printMode = 'silent';
			$c.ext.openOzReport(data, opts);
		} else {
			opts.type = "";
			opts.printMode = "";
			opts.exportFormat = "";
			opts.exportMode = "";

			$c.ext.printOzReport(data, opts);
		}

    } else {    

        //일괄print (viewer안띄운다)

        //OZStartBatch(); 
        var printCnt = 0;
        var firstOdrNo = "";
        var chkOdrNo = "";
        var v_odrNo = "";

        for(var i = 0; i < lenListOdrNo; i++ ) {
            v_odrNo = scwin.listOdrNo[i];

            if(printCnt == 0) firstOdrNo = v_odrNo;
            if(chkOdrNo == v_odrNo) continue;
            if(chkOdrNo !== v_odrNo) chkOdrNo = v_odrNo;

            // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
            const data = {
                odiName:"op_202_02_05r",
                reportName: "/ds/op/wrkplan/transwrkplan/op_202_02_05r.ozr",
                odiParam: {
                    odrNo : v_odrNo
                  , sortCd : acb_lc_sortCd.getValue()
                },
                viewerParam: {
                    useprogressbar: false
                },
                formParam: {}
            };

            $c.ext.printOzReport(data, {});

            printCnt++;
        }

        //OZExecuteBatch();
        if(printCnt == 1) $c.win.alert(firstOdrNo+"의 오더Sheet를 프린터로 전송했습니다.");
        if(printCnt > 1) $c.win.alert(firstOdrNo+"외에 "+(printCnt-1)+"건의 오더Sheet를 프린터로 전송했습니다.");

    }
};


/**
 * Windows Close
 */
scwin.btn_close_onclick = function (e) {
    $c.win.closePopup();
};
